insert into rules (category, code, title, body, penalty, severity, tags, order_index) values
('الشروط العامة', null, '1.1 - مشروع OneState هو مشروع لعب تمثيلي يشار إليه فيما بعد (مشروع OneState) و هو يدور في ولاية...', '1.1 - مشروع OneState هو مشروع لعب تمثيلي يشار إليه فيما بعد (مشروع OneState) و هو يدور في ولاية أمريكية 1.2 - من لحظة التسجيل في مشروع ون ستيت، يُعتبر كل مستخدم (يشار إليه فيما بعد بـ "اللاعب") على دراية بجميع القواعد ويكون مسؤولًا عن الالتزام بها. 1.3 - أي تفاعل داخل مشروع OneState يعتمد على الاحترام المتبادل والسلوك المهذب تجاه اللاعبين الآخرين. 1.4 - تنطبق هذه القواعد على جميع اللاعبين، بغض النظر عن حالتهم في مشروع OneState. 1.5 - تحتفظ إدارة مشروع OneState (يشار إليها فيما بعد بـ "الإدارة") بالحق في إضافة وتغيير القواعد الحالية حسب الحاجة، في أي وقت. 1.6 - سيتم إخطار اللاعبين فورًا بأي تغييرات في القواعد الحالية من خلال رسائل إعلامية على وسائل الشبكات الاجتماعية الرسمية لمشروع OneState. 1.7 - الحسابات المرتبطة هي الحسابات التي ترتبط بواحد أو أكثر من الخصائص المشتركة. 1.8 - الهدف الرئيسي من مشروع OneState هو خلق والحفاظ على تجربة لعب مريحة وممتعة لكل لاعب. 1.9 - يمكن للاعب استخدام الأمر داخل اللعبة ‎/help‎ للحصول على المساعدة حول مشروع OneState. 1.10 - في حال تعلق اللاعب داخل عناصر اللعبة، يُسمح له باستخدام الأمر داخل اللعبة ‎/respawn‎. 1.11 - عند إرسال رسالة لا تتعلق بلعب الأدوار (RolePlay)، يجب استخدام الدردشة غير المتعلقة بـ RP. ولإرسال رسالة في دردشة NRP، يجب على اللاعب استخدام الأمر ‎/n‎. 1.12 - يجب أن يكون التواصل في الدردشة غير التمثيلية مبنيًا على الاحترام المتبادل والسلوك الصحيح تجاه اللاعبين الآخرين.', null, 'MEDIUM', '[]'::jsonb, 10),
('مساعدة اللاعب', null, '1.8 - يمكن للاعب استخدام الأمر داخل اللعبة help وإدخاله في الدردشة داخل اللعبة للحصول على المسا...', '1.8 - يمكن للاعب استخدام الأمر داخل اللعبة help وإدخاله في الدردشة داخل اللعبة للحصول على المساعدة من مسؤول الخادم. 1.9 - في الحالات التي تَعلَق فيها الشخصية في عناصر اللعبة، يمكن للاعب استخدام الأمر respawn وإدخاله في الدردشة داخل اللعبة. سيؤدي هذا الإجراء إلى قتل الشخصية المذكورة، وستظهر مجددًا في المستشفى. 1.10 - عندما تكون الرسائل التي يرسلها اللاعب لا تتعلق بلعب الأدوار، يجب استخدام الدردشة غير المتعلقة بلعب الأدوار. لإرسال رسالة في الدردشة غير المتعلقة بلعب الأدوار، يجب على اللاعب استخدام الأمر n/ وإدخاله في الدردشة داخل اللعبة. 1.11 - التواصل في الدردشة غير المتعلقة بلعب الأدوار يخضع للقواعد الحالية ويعتمد على الاحترام المتبادل والسلوك المهذب تجاه اللاعبين الآخرين. 1.12 - سيؤدي إلغاء أكثر من 5 عقود إيجار خلال 30 من الأيام إلى حظر ميزة الإلغاء لمدة 30 من الأيام القادمة.', null, 'MEDIUM', '[]'::jsonb, 20),
('العقوبات والجزاءات', 'RP1', '2.1 - تُحدَّد إجراءات الإدارة وفقًا للقواعد الحالية لمشروع OneState. 2.2 - سيؤدي عدم الامتثال ل...', '2.1 - تُحدَّد إجراءات الإدارة وفقًا للقواعد الحالية لمشروع OneState. 2.2 - سيؤدي عدم الامتثال للقواعد الحالية لمشروع OneState من قِبَل اللاعب إلى تلقي عقوبة من الإدارة تتوافق مع الانتهاك. 2.3 - عند إصدار العقوبة، سيشير المسؤول إلى القاعدة التي انتهكها اللاعب باستخدام اختصار خاص (على سبيل المثال، RP1، CHAT4). وترِد أدناه قائمة بالانتهاكات والاختصارات المقابلة لها.', '، سيشير المسؤول إلى القاعدة التي انتهكها اللاعب باستخدام اختصار خاص (على سبيل المثال، RP1، CHAT4)', 'MEDIUM', '[]'::jsonb, 30),
('قواعد الألقاب', 'NAME1', '3.1 - NAME1 - استخدام لقب غير متعلق بلعب الأدوار استخدام لقب (اسم شخصية) لا يتوافق مع معايير لع...', '3.1 - NAME1 - استخدام لقب غير متعلق بلعب الأدوار استخدام لقب (اسم شخصية) لا يتوافق مع معايير لعب الأدوار لشخصية داخل عالم لعبة OneState. العقوبة: تغيير اللقب قسرًا. يجب على اللاعب اختيار لقب جديد متوافق مع لعب الأدوار، وإلا فسيتم تعيين لقب من قِبَل الإدارة. ‏3.2 - NAME2 - استخدام لقب مسيء غير متعلق بلعب الأدوار استخدام كلمات مسيئة أو بذيئة كلقب، بالإضافة إلى الكلمات المرتبطة بالأفعال غير اللائقة أو الموضوعات المحظورة في مشروع ONESTATE. تنطبق هذه القاعدة على الألقاب التي تم إنشاؤها بأي لغة. العقوبة: تغيير اللقب قسرًا، ويتم تعيين اللقب الجديد من قِبَل الإدارة.', 'تغيير اللقب قسرًا', 'MEDIUM', '[]'::jsonb, 40),
('قواعد الحسابات', 'AC1', '4.1 - حساب المستخدم هو حساب أنشأه اللاعب للوصول إلى مشروع OneState (المشار إليه فيما بعد باسم ا...', '4.1 - حساب المستخدم هو حساب أنشأه اللاعب للوصول إلى مشروع OneState (المشار إليه فيما بعد باسم الحساب). 4.2 - الحسابات التابعة هي حسابات تابعة للاعب واحد مرتبطة بواحدة أو أكثر من الخصائص (بما في ذلك، على سبيل المثال لا الحصر: تم إنشاؤها من نفس الجهاز، وتم تسجيل الدخول إليها من نفس عنوان IP، وما إلى ذلك). 4.3 - الحسابات المسجلة على خوادم مشروع OneState هي ملكية فكرية لشركة CHILLBASE LTD (يشار إليها فيما بعد باسم الشركة). 4.4 - تحتفظ الشركة بالحقوق الحصرية لجميع الحسابات التي ينشئها اللاعبون على خوادم مشروع OneState. 4.5 - لن تطلب إدارة الشركة وموظفوها أبدًا البيانات الشخصية للاعبين، بما في ذلك تسجيلات الدخول وكلمات المرور ومعلومات الحساب الأخرى و/أو تفاصيل الدفع، ولن يطلبوا منك اتباع روابط خارجية. احذر من المحتالين! 4.6 - الإدارة ليست مسؤولة عن سلامة أصول اللعبة، بما في ذلك تلك المخصصة للاعبين. لا تشارك بيانات حسابك مع أي شخص! 4.7 - لا تشارك الإدارة في استعادة أصول اللعبة في حالة اختراق الحساب أو نقله إلى أطراف ثالثة. ‏4.8 - AC1 - بيع و/أو محاولة بيع حساب ‏بيع و/أو محاولة بيع حساب على مواقع خارجية أو خوادم مشروع ONESTATE. ‏العقوبة: حظر دائم لجميع الحسابات المرتبطة. ‏4.9 - AC2 - نقل و/أو محاولة نقل حساب ‏نقل و/أو محاولة نقل حساب على مواقع خارجية أو خوادم مشروع ONESTATE. ‏ العقوبة: حظر دائم للحساب المنقول. ‏4.10 - AC3 - إنشاء أكثر من 3 حسابات ‏إنشاء أكثر من 3 حسابات بواسطة لاعب واحد. ‏العقوبة: حظر دائم للحساب الرابع وكل الحسابات اللاحقة والمرتبطة. ‏4.11 - AC4 - اختراق الحساب ‏اختراق و/أو الوصول غير المصرح به إلى حساب لاعب آخر. ‏العقوبة: حظر دائم للحسابات التابعة للمخالف، وإغلاق الحساب المخترَق بإشعار عبر البريد الإلكتروني للمالك، يليه إعادة تعيين كلمة المرور للحساب المخترَق. ‏4.12 - AC5 - التجارة في العالم الحقيقي ‏بيع و/أو شراء و/أو محاولة بيع أو شراء عقارات داخل اللعبة أو عملة افتراضية مقابل أموال حقيقية. ‏العقوبة: حظر دائم لجميع الحسابات المرتبطة بالمخالفين.', 'حظر دائم لجميع الحسابات المرتبطة', 'HIGH', '[]'::jsonb, 50),
('قواعد الدردشة والتواصل', 'CHAT1', '6.1 - CHAT1 - إهانة لاعب ‏أي إهانة موجّهة إلى لاعب آخر من دون سبب وجيه في لعب الأدوار. ‏العقوبة...', '6.1 - CHAT1 - إهانة لاعب ‏أي إهانة موجّهة إلى لاعب آخر من دون سبب وجيه في لعب الأدوار. ‏العقوبة : حظر الحساب لمدة 24 ساعة. ‏', 'حظر الحساب لمدة 24 ساعة', 'HIGH', '[]'::jsonb, 60),
('قواعد الدردشة والتواصل', 'CHAT16', '‏6.16 - CHAT16 - استخدام لغة غير رسمية ‏يجب أن تُجرى المحادثات داخل اللعبة باللغة الإقليمية للخ...', '‏6.16 - CHAT16 - استخدام لغة غير رسمية ‏يجب أن تُجرى المحادثات داخل اللعبة باللغة الإقليمية للخادم. ويُستثنى من ذلك المحادثات التي تدور ضمن مجموعة صغيرة من اللاعبين (5 لاعبين أو أقل) شريطة ألا تتعارض مع مسار لعب الأدوار للاعبين الآخرين. ‏العقوبة : كتم الدردشة الصوتية والنصية لمدة 10 دقائق، أو حظر الحساب لمدة تصل إلى 12 ساعة (حسب عدد الانتهاكات المتكررة). ‏', 'كتم الدردشة الصوتية والنصية لمدة 10 دقائق، أو حظر الحساب لمدة تصل إلى 12 ساعة (حسب عدد الانتهاكات المتكررة)', 'HIGH', '[]'::jsonb, 70),
('الانتهاكات الجسيمة', 'ABUSE1', '7.1 - ABUSE1 - إساءة استخدام وضع اللعبة ‏استخدام أي أخطاء أو ثغرات أمنية أو ميزات غير محسوبة في...', '7.1 - ABUSE1 - إساءة استخدام وضع اللعبة ‏استخدام أي أخطاء أو ثغرات أمنية أو ميزات غير محسوبة في وضع اللعبة للحصول على ميزة على اللاعبين الآخرين و/أو لتعطيل عملية اللعب. بما في ذلك، على سبيل المثال لا الحصر: إطلاق النار عبر الجدران، أو المغادرة في أثناء مشاهد لعب الأدوار، أو استخدام بطاقات الخروج من السجن لتجاوز عقوبات الإدارة. ‏العقوبة : حظر الحساب من يوم واحد حتى 30 يومًا. ‏', 'حظر الحساب من يوم واحد حتى 30 يومًا', 'HIGH', '[]'::jsonb, 80),
('قواعد العصابات', 'CLAN1', '9.1 - CLAN1 - أسماء العصابات والأوصاف والرتب ‏يجب ألا ينتهك اسم العصابة ووصفها، وكذلك أسماء الر...', '9.1 - CLAN1 - أسماء العصابات والأوصاف والرتب ‏يجب ألا ينتهك اسم العصابة ووصفها، وكذلك أسماء الرتب داخل العصابة، أي قواعد لمشروع ONESTATE، وألا تحتوي على إهانات أو كلمات محظورة على منصات البث، بما في ذلك Twitch. ‏العقوبة : التغيير القسري لاسم العصابة أو وصفها. ‏', 'التغيير القسري لاسم العصابة أو وصفها', 'MEDIUM', '[]'::jsonb, 90),
('اللعب غير التمثيلي (NRP) - RP4 - RP6:', null, 'ما هو اللعب غير التمثيلي؟ الإجراءات التي تكون غير واقعية أو تروج للعب تمثيلي بجودة منخفضة تُعتب...', 'ما هو اللعب غير التمثيلي؟ الإجراءات التي تكون غير واقعية أو تروج للعب تمثيلي بجودة منخفضة تُعتبر لعبًا غير تمثيلي. إليك أمثلة على الإجراءات التي تُعتبر غير تمثيلية على خادمنا (ولكنها ليست مقتصرة على): 1) استدراج الشرطة - استفزاز رد فعل من خدمات الطوارئ بدون سبب واقعي؛ 2) استدراج الجنود - استفزاز رد فعل من عضو فصيل الجيش؛ 3) لا يمكنك التجمع بالقرب من بوابة القاعدة (إلا خلال الحدث)؛ 4) لا يمكنك سحب الأسلحة في وجود الجنود والشرطة (في هذه الحالة، يحق للشرطة اعتقالك وللجنود فتح النار عليك)؛ 5) حمل الأسلحة علنًا في المدينة ممنوع؛ 6) مهاجمة ضابط شرطة عندما لا تكون مطلوبًا والضابط لا يحاول اعتقالك؛ 7) أخذ رجال الشرطة والجنود كرهائن؛ 8) القتل الرحيم - طلب أن يتم قتلك بواسطة صديق؛ 9) القيام بحركات بهلوانية غير واقعية أو استخدام مركبة باهظة الثمن للاصطدام بمركبات أخرى؛ 10) استدعاء المركبات أو استدعاء أي مركبة في الماء؛ 11) السباحة في الماء لمدة غير واقعية أو بدون وجهة محددة أثناء المطاردة؛ 12) اللاعبين الذين ينفصلون عن اللعبة أثناء اللعب التمثيلي يجب أن يعودوا ويبلغوا الأطراف الأخرى لاستئناف اللعبة التمثيلية. إذا لم تتمكن من العودة، فقد يُعفى عنك بعد تقديم دليل؛ 13) تجاهل الأوامر التمثيلية الموجهة إليهم، مثل /do؛ 14) الخروج المتكرر عن الشخصية أثناء اللعب التمثيلي؛ 15) قاعدة الحياة الجديدة - العودة إلى نفس المكان الذي قُتلت فيه ومطاردة اللاعبين الذين قتلوك سابقًا. يجب عليك أن تنسى كل ما حدث لك قبل 15 دقيقة من موتك؛ 16) انتظار اللاعبين الذين أُعيد إحياؤهم بالقرب من المستشفى لقتلهم أو إلحاق الضرر بهم؛ 17) يجب عليك التصرف كما لو أنك تحترم وتخاف من سلطات إنفاذ القانون (الشرطة)، أي أنك لا تريد أن تُقبض عليك أو تواجه مشاكل مع الشرطة؛ 18) القيادة بسرعات مفرطة طوال الوقت، والاصطدام بالأشياء، أو السيارات الأخرى، أو اللاعبين الآخرين؛ 19) الدخول في حادث والقيادة بعيدًا وكأن شيئًا لم يحدث.', null, 'MEDIUM', '[]'::jsonb, 100),
('لعب دور الخوف', 'RP4', '(Fear Roleplay - FRP) - RP4, RP5, RP6: ما هو لعب دور الخوف؟ بينما لا يموت شخصيتك بشكل دائم، يجب...', '(Fear Roleplay - FRP) - RP4, RP5, RP6: ما هو لعب دور الخوف؟ بينما لا يموت شخصيتك بشكل دائم، يجب أن يتصرف كما لو كان عرضة للموت بسبب إمكانية تعرضه للإصابة أو فقدان حياته. أمثلة على أفعال تُعتبر إخفاقًا في لعب الدور في السيرفر (لكنها ليست محدودة بهذه الأمثلة): 1) عندما تكون على الأقدام أو الدراجة ويُوجه سلاح نحوك من مسافة قريبة. 2) عندما تكون داخل مركبة متوقفة أو مُطفأة ويُوجه سلاح نحوك من مسافة قريبة. 3) عندما يقوم المعتدي بخفض سلاحه للكتابة أو لعب الدور، تظل حياتك في خطر مباشر. 4) قيادة مركبة خلال تبادل إطلاق نار نشط لأكثر من مرة. 5) إذا كنت تحت تهديد السلاح من قبل الشرطة، فلا يمكنك ببساطة إخراج سلاحك وإطلاق النار عليهم.', null, 'HIGH', '[]'::jsonb, 110),
('اللعب بأفضلية', 'RP4', '(Powergaming) - RP4, RP5, RP6: ما هو اللعب بأفضلية ؟ اللعب بأفضلية هو استغلال ميكانيكيات اللعبة...', '(Powergaming) - RP4, RP5, RP6: ما هو اللعب بأفضلية ؟ اللعب بأفضلية هو استغلال ميكانيكيات اللعبة أو أي معلومات خارجية أو مفهوم في لعب الأدوار لصالح شخصيتك أو قصتك، مما يمنحك ميزة غير عادلة أو غير واقعية. أمثلة على أفعال تُعتبر لعبًا بأفضلية في السيرفر (لكنها ليست محدودة بهذه الأمثلة): 1)إ ذا كان أحدهم يوجه سلاحًا نحوك ولا تخرج من السيارة (في اللعبة، لا يمكن إيذاء اللاعبين داخل السيارة). 2) لعب أدوار قسري لا يعطي اللاعب الآخر فرصة للرد بلعب دوره الخاص. يجب منح اللاعبين الآخرين فرصة للرد ولعب نتائج الأفعال. 3) لعب أدوار غير واقعية مثل امتلاك قوة خارقة. 4) استخدام أي معلومات من خارج اللعبة لتحقيق ميزة.', null, 'MEDIUM', '[]'::jsonb, 120),
('نصائح أساسية:', null, '1) يجب أن تكون أسماء الشخصيات واقعية ولا تشبه أسماء العالم الحقيقي أو أشخاصًا مشهورين. على سبيل...', '1) يجب أن تكون أسماء الشخصيات واقعية ولا تشبه أسماء العالم الحقيقي أو أشخاصًا مشهورين. على سبيل المثال، James_Smith اسم مقبول، بينما Brad_Pitt غير مقبول. وينطبق هذا أيضًا على الأسماء المضحكة مثل Ben_Dover. 2) يُسمح للاعبين بالانخراط في لعب الأدوار الشريرة أو التعذيب أو الأدوار المثيرة للاشمئزاز فقط إذا أعطى جميع اللاعبين المعنيين، بما في ذلك الشهود، موافقة مسبقة خارج نطاق اللعبة (OOC). يجب أن يتم لعب هذه الأدوار في مناطق خاصة بعيدًا عن الأماكن العامة أو المناطق التي يزورها اللاعبون عادةً، مثل السجن. 3) يُعتبر استخدام الإهانات العرقية لعبًا مثيرًا للاشمئزاز، ويجب أن يعطي جميع الأطراف المعنيين موافقة مسبقة خارج نطاق اللعبة قبل استخدامها. بالإضافة إلى ذلك، يجب أن يكون لاستخدام هذه الإهانات سياق منطقي يعكس دوافع شخصيتك داخل اللعبة.', null, 'MEDIUM', '[]'::jsonb, 130),
('القواعد العامة', null, '1.1 المجموعات (الفصيل) هي منظمات داخل اللعبة يمكن أن تكون حكومية أو غير حكومية. معظم اللاعبين س...', '1.1 المجموعات (الفصيل) هي منظمات داخل اللعبة يمكن أن تكون حكومية أو غير حكومية. معظم اللاعبين سيكونون إما في فصائل أو يتفاعلون معها بشكل متكرر، لذلك من المهم التحكم في الفصائل للحفاظ على أجواء اللعب التمثيلي (Role Play) في اللعبة؛ 1.2 قائد الفصيل هو لاعب يكون رئيس الفصيل، وهو مسؤول عن توظيف الموظفين، والتحكم في عملهم وجميع العمليات الداخلية المتعلقة بحياة الفصيل؛ 1.3 يتم تعيين قائد الفصيل في منصب القائد بواسطة المسؤول/مدير المجتمع من خلال مقابلة، وتفتح طلبات التقديم لمنصب القائد في الديسكورد، ويمكن لأي شخص تقديم طلب؛ 1.4 لكل قائد نواب يساعدونه في إدارة الفصيل. يجب على جميع النواب الالتزام بنفس القواعد مثل القادة؛ 1.5 الحد الأقصى لعدد النواب هو 2.', null, 'MEDIUM', '[]'::jsonb, 140),
('قواعد قادة الفصائل ونوابهم', null, '2.1 يدير قائد الفصيل الفصيل بمساعدة مسؤول الفصيل (المسؤول المسؤول عن الفصيل). يجب مناقشة أي قرا...', '2.1 يدير قائد الفصيل الفصيل بمساعدة مسؤول الفصيل (المسؤول المسؤول عن الفصيل). يجب مناقشة أي قرارات مع مسؤول الفصيل؛ 2.2 الحد الأدنى لمدة القيادة هو شهر واحد؛ 2.3 يجب أن يكون القائد متواجدًا عبر الإنترنت يوميًا لمدة لا تقل عن 4 ساعات؛ 2.4 عند ترك منصب القائد بقراره الشخصي، يمكن للاعب التقديم للمنصب مرة أخرى بعد شهر واحد من نهاية فترته؛ 2.5 عند إزالته من منصب القائد بسبب انتهاكات، يُمنع على اللاعب تولي هذا المنصب مرة أخرى؛ 2.6 لا يجب أن تؤثر العلاقات الشخصية بين القائد واللاعبين الآخرين على أسلوب اللعب؛ 2.7 الحد الأدنى للعمر الذي يمكن من خلاله تولي منصب القائد هو 16 عامًا.', null, 'MEDIUM', '[]'::jsonb, 150),
('يُمنع على القادة ونوابهم القيام بالأمور التالية', null, '3.1 يُمنع انتهاك قواعد الخادم (السيرفر)؛ 3.2 يُمنع السماح بأي شكل من أشكال الفساد؛ 3.3 يُمنع فص...', '3.1 يُمنع انتهاك قواعد الخادم (السيرفر)؛ 3.2 يُمنع السماح بأي شكل من أشكال الفساد؛ 3.3 يُمنع فصل الموظفين بدون أدلة على المخالفة؛ 3.4 يُمنع إهانة اللاعبين/الموظفين في الفصيل (ما لم يكن ذلك جزءًا من اللعب التمثيلي)؛ 3.5 يُمنع التدخل في عملية اللعبة بناءً على العلاقات الشخصية مع اللاعبين؛ 3.6 يُمنع بيع المناصب مقابل أموال اللعب أو الأموال الحقيقية؛ 3.7 يُمنع على القائد التقدم لمنصب مساعد أو لمنصب قائد في خادم آخر أو فصيل آخر.', null, 'MEDIUM', '[]'::jsonb, 160),
('العقوبات على القائد ونوابه', null, '4.1 تُفرض العقوبات على القائد ونوابه من قبل مدير المجتمع أو مسؤول الفصيل؛ 4.2 لكل انتهاك، يحصل ...', '4.1 تُفرض العقوبات على القائد ونوابه من قبل مدير المجتمع أو مسؤول الفصيل؛ 4.2 لكل انتهاك، يحصل القائد أو نائبه على تحذير واحد؛ 4.3 3 تحذيرات تعادل توبيخًا واحدًا؛ 4.4 3 توبيخات تعني الإزالة من منصب القائد أو النائب؛ 4.5 يحصل القائد أو النواب على تحذير واحد عند انتهاك أي من قواعد الخادم أو القواعد العامة للفصائل أو قواعد فصيل الشرطة؛ 4.6 في حالة الانتهاكات الجسيمة، يمكن للإدارة العليا إصدار توبيخات بدلاً من التحذيرات.', null, 'MEDIUM', '[]'::jsonb, 170),
